import operator

def check_alert_conditions(current_metrics, alert_rules):
    op_map = {
        '>': operator.gt,
        '<': operator.lt,
        '>=': operator.ge,
        '<=': operator.le,
        '==': operator.eq,
        '!=': operator.ne,
    }

    for rule in alert_rules:
        metric_name = rule.get('metric')
        operator_str = rule.get('operator')
        threshold = rule.get('threshold')

        if not all([metric_name, operator_str, threshold is not None]):
            continue

        if metric_name not in current_metrics:
            continue

        current_value = current_metrics[metric_name]

        if operator_str not in op_map:
            continue

        comparison_func = op_map[operator_str]

        try:
            if comparison_func(current_value, threshold):
                return True
        except TypeError:
            continue

    return False

